SELECT * FROM (SELECT * FROM (SELECT * FROM (SELECT * FROM (SELECT * FROM (/*<Unsupported Retrieve with arguments <modeltype: urn:healthit-gov:qdm:v5_6, templateId: PositiveEncounterPerformed>*/) AS NonElectiveEncounter WHERE ((DATEDIFF(NonElectiveEncounter.relevantPeriod.high, NonElectiveEncounter.relevantPeriod.low) <= 120) AND NonElectiveEncounter.relevantPeriod.high BETWEEN @Measurement_Period.low AND @Measurement_Period.high)) AS NonElectiveEncounter WHERE EXISTS (SELECT * FROM (NonElectiveEncounter.diagnoses) AS Diagnosis WHERE ((Diagnosis.rank = 1) AND (/* InValueSet check for element: <Diagnosis.code>, valueset <urn:oid:2.16.840.1.113883.3.117.1.7.1.212> */ OR /* InValueSet check for element: <Diagnosis.code>, valueset <urn:oid:2.16.840.1.113883.3.117.1.7.1.247> */)))) AS AllStrokeEncounter WHERE (floor(months_between(AllStrokeEncounter.relevantPeriod.low, to_date(/*<Unsupported Retrieve with arguments <modeltype: urn:healthit-gov:qdm:v5_6, templateId: Patient>*/.birthDatetime)) / 12) >= 18)) AS EncounterWithAge WHERE EXISTS (SELECT * FROM (EncounterWithAge.diagnoses) AS Diagnosis WHERE (/* InValueSet check for element: <Diagnosis.code>, valueset <urn:oid:2.16.840.1.113883.3.117.1.7.1.247> */ AND (Diagnosis.rank = 1)))) AS IschemicStrokeEncounter WHERE ((((/* InValueSet check for element: <IschemicStrokeEncounter.dischargeDisposition>, valueset <urn:oid:2.16.840.1.113883.3.117.1.7.1.87> */ OR /* InValueSet check for element: <IschemicStrokeEncounter.dischargeDisposition>, valueset <urn:oid:2.16.840.1.113883.3.117.1.7.1.308> */) OR /* InValueSet check for element: <IschemicStrokeEncounter.dischargeDisposition>, valueset <urn:oid:2.16.840.1.113883.3.117.1.7.1.309> */) OR /* InValueSet check for element: <IschemicStrokeEncounter.dischargeDisposition>, valueset <urn:oid:2.16.840.1.113883.3.117.1.7.1.209> */) OR /* InValueSet check for element: <IschemicStrokeEncounter.dischargeDisposition>, valueset <urn:oid:2.16.840.1.113883.3.117.1.7.1.207> */)